import React, { useState, useEffect } from "react";
import { useParams, useNavigate } from "react-router-dom";
import Navbar from "./Navbar";
import Footer from "./Footer";

function Doctorprofile() {
  const { doctor_id } = useParams();
  const navigate = useNavigate();

  const [doctor, setDoctor] = useState(null);
  const [availableDays, setAvailableDays] = useState([]);
  const [availableTimes, setAvailableTimes] = useState([]);
  const [date, setDate] = useState("");
  const [time, setTime] = useState("");

  // ⭐ Feedback states
  const [feedbacks, setFeedbacks] = useState([]);
  const [rating, setRating] = useState("");
  const [comment, setComment] = useState("");

  // ✅ Fetch doctor
  useEffect(() => {
    fetch(`http://127.0.0.1:8000/doctor-details/${doctor_id}/`, {
      headers: {
        Authorization: `Token ${localStorage.getItem("token")}`,
      },
    })
      .then((res) => res.json())
      .then((data) => {
        setDoctor(data.doctor);
        setAvailableDays(data.doctor.available_days || []);
        setAvailableTimes(data.doctor.available_time_slots || []);
      })
      .catch((err) => console.error(err));
  }, [doctor_id]);

  // ✅ Fetch feedback
  useEffect(() => {
    fetch(`http://127.0.0.1:8000/doctor-feedback/${doctor_id}/`, {
      headers: {
        Authorization: `Token ${localStorage.getItem("token")}`,
      },
    })
      .then((res) => res.json())
      .then((data) => setFeedbacks(data))
      .catch((err) => console.error(err));
  }, [doctor_id]);

  // ⭐ Average rating
  const avgRating =
    feedbacks.length > 0
      ? (
          feedbacks.reduce((sum, fb) => sum + fb.rating, 0) /
          feedbacks.length
        ).toFixed(1)
      : 0;

  const getDayName = (dateStr) => {
    return new Date(dateStr).toLocaleDateString("en-US", {
      weekday: "long",
    });
  };

  const handleDateChange = (e) => {
    const selectedDate = e.target.value;
    const dayName = getDayName(selectedDate);

    if (!availableDays.includes(dayName)) {
      alert(`Doctor not available on ${dayName}`);
      setDate("");
      return;
    }

    setDate(selectedDate);
  };

  const handleNext = () => {
    if (!date || !time) {
      alert("Please select date and time");
      return;
    }

    navigate("/appointment", {
      state: { doctor, date, time, doctor_id },
    });
  };

  // ✅ Submit feedback
  const handleSubmitFeedback = () => {
    if (!rating || !comment) {
      alert("Please add rating and comment");
      return;
    }

    fetch(`http://127.0.0.1:8000/doctor-feedback/${doctor_id}/`, {
      method: "POST",
      headers: {
        "Content-Type": "application/json",
        Authorization: `Token ${localStorage.getItem("token")}`,
      },
      body: JSON.stringify({ rating, comment }),
    })
      .then((res) => res.json())
      .then((data) => {
        setFeedbacks([data, ...feedbacks]);
        setRating("");
        setComment("");
      })
      .catch((err) => console.error(err));
  };

  if (!doctor) return <h2 style={styles.loading}>Loading...</h2>;

  return (
    <div style={styles.container}>
      <Navbar />

      <div style={styles.main}>
        <div style={styles.card}>
          
          {/* IMAGE */}
          <div style={styles.left}>
            <img
              src={
                doctor.image ||
                "https://cdn-icons-png.flaticon.com/512/387/387561.png"
              }
              alt={doctor.name}
              style={styles.image}
            />
          </div>

          {/* DETAILS */}
          <div style={styles.right}>
            <h2>{doctor.name}</h2>
            <p><b>Specialization:</b> {doctor.field}</p>
            <p><b>Experience:</b> {doctor.experience}</p>
            <p><b>Qualification:</b> {doctor.qualification}</p>
            <p><b>Available Days:</b> {availableDays.join(", ")}</p>

            {/* BOOKING */}
            <div style={styles.bookingSection}>
              <label>Select Date:</label>
              <input
                type="date"
                value={date}
                min={new Date().toISOString().split("T")[0]}
                onChange={handleDateChange}
                style={styles.input}
              />

              <label>Select Time:</label>
              <select
                value={time}
                onChange={(e) => setTime(e.target.value)}
                style={styles.input}
              >
                <option value="">Select Time</option>
                {availableTimes.map((t, i) => (
                  <option key={i}>{t}</option>
                ))}
              </select>

              <button style={styles.button} onClick={handleNext}>
                Book Appointment
              </button>
            </div>

            {/* ⭐ PROFESSIONAL REVIEW SECTION */}
            <div style={styles.reviewContainer}>
              <h3>Patient Reviews</h3>

              <div style={styles.ratingSummary}>
                <h2>{avgRating} ⭐</h2>
                <p>{feedbacks.length} reviews</p>
              </div>

              <div style={styles.reviewForm}>
                <select
                  value={rating}
                  onChange={(e) => setRating(e.target.value)}
                  style={styles.input}
                >
                  <option value="">Select Rating</option>
                  <option value="5">⭐⭐⭐⭐⭐ Excellent</option>
                  <option value="4">⭐⭐⭐⭐ Good</option>
                  <option value="3">⭐⭐⭐ Average</option>
                  <option value="2">⭐⭐ Poor</option>
                  <option value="1">⭐ Bad</option>
                </select>

                <textarea
                  placeholder="Share your experience..."
                  value={comment}
                  onChange={(e) => setComment(e.target.value)}
                  style={styles.textarea}
                />

                <button onClick={handleSubmitFeedback} style={styles.submitBtn}>
                  Submit Review
                </button>
              </div>

              <div style={styles.reviewList}>
                {feedbacks.length > 0 ? (
                  feedbacks.map((fb) => (
                    <div key={fb.id} style={styles.reviewCard}>
                      <div style={styles.reviewHeader}>
                        👤 <b>{fb.user_name}</b>
                      </div>
                      <div>{"⭐".repeat(fb.rating)}</div>
                      <p>{fb.comment}</p>
                    </div>
                  ))
                ) : (
                  <p>No reviews yet</p>
                )}
              </div>
            </div>

          </div>
        </div>
      </div>

      <Footer />
    </div>
  );
}

export default Doctorprofile;

/* 🎨 STYLES */
const styles = {
  container: { display: "flex", flexDirection: "column", minHeight: "100vh", background: "#f4f6f9" },
  main: { flex: 1, display: "flex", justifyContent: "center", alignItems: "center" },
  card: { display: "flex", background: "#fff", padding: "30px", borderRadius: "10px", width: "750px", gap: "30px" },
  left: { display: "flex", alignItems: "center" },
  image: { width: "150px", height: "150px", borderRadius: "50%" },
  right: { flex: 1 },
  bookingSection: { marginTop: "20px", display: "flex", flexDirection: "column", gap: "10px" },
  input: { padding: "8px", borderRadius: "5px", border: "1px solid #ccc" },
  button: { padding: "10px", background: "#2c3e50", color: "#fff", border: "none", borderRadius: "5px" },

  reviewContainer: { marginTop: "40px", background: "#f9fafb", padding: "20px", borderRadius: "10px" },
  ratingSummary: { display: "flex", gap: "10px", alignItems: "center" },
  reviewForm: { display: "flex", flexDirection: "column", gap: "10px", marginTop: "10px" },
